// Transform all product images to use picsum.photos with product name as seed
// This ensures unique, relevant placeholder images for each product
productTemplates.forEach(product => {
  const seed = encodeURIComponent(product.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').slice(0, 50));
  product.images = product.images.map((img, i) => ({
    url: `https://picsum.photos/seed/${seed}-${i}/600/600`
  }));
});

